import React from 'react'
import '../styleNightlife.css'
import DetailParralax from './nature_components/DetailParralax'
export default function NatureDetails(props) {
    let chache='';
    if(localStorage.getItem('cardData')){
        chache=JSON.parse(localStorage.getItem('cardData'));
    } 
    const{
        natureTitle,
        natureMap,
        natureText,
        imgBanner,
        imgBannerBg,
        virtualLink,
        imgCollection,
        virualMapLink,
    } = chache;
        return (   
            <>
                <DetailParralax natureTitle={natureTitle} imgBanner={imgBanner} natureText={natureText} natureMap={natureMap} imgBannerBg={imgBannerBg} virtualLink={virtualLink} imgCollection={imgCollection} virualMapLink={virualMapLink}/>
            </>  
    
        )
    
}